={{
  (() => {
    // 1. Pega o objeto key (ou objeto vazio para evitar erro)
    const key = $json?.body?.messages[0].sender ?? {};

    // 2. Lista TODOS os valores que forem string
    const values = Object.values(key).filter(v => typeof v === 'string');

    // 3. Procura, na ordem de preferência, o número real (@s.whatsapp.net)
    const real = values.find(v => v.endsWith('@s.whatsapp.net'));
    if (real) return real.split('@')[0];

    // 4. Se não achou, descarta @lid e @g.us (grupos)
    const alt = values.find(v => !/@(lid|g\.us)$/.test(v));
    if (alt) return alt.split('@')[0];

    // 5. Se ainda não achou, devolve null
    return null;
  })()
}}

