(() => {
  const safeJson = (v) => {
    try {
      if (v === undefined || v === null) return null;
      return typeof v?.toJsonString === 'function' ? v.toJsonString() : JSON.stringify(v);
    } catch (e) {
      return null;
    }
  };

  const truncate = (s, max = 200000) => {
    if (!s) return s;
    return s.length > max ? s.slice(0, max) : s;
  };

  // formato mysql seguro
  const fmt = (v) => {
    try {
      return v?.toDateTime?.().format('yyyy-MM-dd HH:mm:ss') ?? null;
    } catch (e) {
      return null;
    }
  };

  const digits = (v) => (v ? String(v).replace(/\D/g, '') : null);
  const s = (v) => (v === undefined || v === null ? "" : String(v));

  const whatsapp = digits($json.phone55);
  const dateStr = fmt($json.updated_at) ?? s($json.updated_at);
  const nome = s($json.pushName);
  const mensagem = s($json.message);
  const evolutionID = s($json.instance);

  // opcional pra auditoria/debug (remove se não tiver coluna)
  const rawStr = safeJson($json);

  return {
    operation: "upsert",
    schema: "ctx_convertix",
    table: "ctx_aquecimento",

    match: { whatsapp },

    data: {
      whatsapp,
      date: dateStr,
      nome,
      mensagem,
      evolutionID,

      // opcionais (só mantém se sua tabela tiver essas colunas)
      // payload: truncate(rawStr, 200000),
      // payload_hash: rawStr ? rawStr.hash('sha256').toLowerCase() : null,
    }
  };
})()
}}

